// Shared validate_input pattern (type=url)
const input = $json || {};
const zalo_user_id = String(input.zalo_user_id || '').trim();
const zalo_msg_id = String(input.zalo_msg_id || '').trim();
const image_url = String(input.image_url || '').trim();
const supplier_hint = input.supplier_hint ? String(input.supplier_hint).trim() : null;
if (!zalo_user_id) throw new Error('zalo_user_id is required');
if (!zalo_msg_id) throw new Error('zalo_msg_id is required');
if (!image_url) throw new Error('image_url is required');

let u;
try { u = new URL(image_url); } catch { throw new Error('image_url must be a valid URL'); }
if (u.protocol !== 'https:') throw new Error('image_url must use https');
const allowHosts = String($env.ALLOWED_FILE_URL_HOSTS || '').split(',').map(s => s.trim()).filter(Boolean);
if (allowHosts.length && !allowHosts.includes(u.hostname)) {
  throw new Error('image_url host is not allowlisted');
}

return [{ json: { zalo_user_id, zalo_msg_id, image_url: u.toString(), supplier_hint } }];
